import getpass
import random
import time
fullscreen = True
assert fullscreen == True, "Fullscreen mode is required for this program to run."


message = "Your files have been encrypted!, put in the correct key to decrypt them!"
print(message)

key = random.randint(1, 1000)
print(f"Simulation cheat: The key is {key}")  # print the key to the console for testing purposes
try:
    text = int(input("Please enter the key to decrypt your files: "))
except ValueError:
    print("Invalid input. Please enter a valid integer.")
    exit()

typed_user = input("Please enter your system username: ")

actual_typed_user = getpass.getuser()  # get the actual system username

if text == key and typed_user == actual_typed_user:
    for i in range(1, 101):
        print(f"Decrypting files... {i}% complete")  # print progress of decryption
        bar = "#" * (i // 2)  # create a progress bar
        print(f"[{bar:<50}]")  # display the progress bar with a width
        print(f"Decrypted file {i}")  # print the decrypted files (this will be empty in this example)
        time.sleep(0.1)  # simulate time taken to decrypt each file

    complete = True
    message = "Decryption complete!"
    print("Files decrypted successfully!")
else:
    complete = False
    message = "Decryption failed!"
    print("Incorrect key or user. Your files remain encrypted.")
    # will keep the files "locked" here
